// // This module decrements the count on each positive edge of the clock when the enable signal is active. Resetting the counter sets it to the maximum value.
module top_module(
  input clk,
  input reset,
  input enable,
  output [3:0] count
);reg [3:0] count_reg;

  always @(posedge clk) begin
    if (reset) begin
      count_reg <= 4'b0;
    end
    else if (enable) begin
      count_reg <= count_reg + 1;
    end
  end

  assign count = count_reg;

endmodule
